arguments.newString:
def get_hip_version():
    hipconfig = shutil.which("hipconfig")
    if hipconfig is None:
        hipconfig = os.path.join(
            os.environ.get("ROCM_PATH") or os.environ.get("ROCM_HOME") or "/opt/rocm",
            "bin", "hipconfig"
        )
    if not os.path.exists(hipconfig):
        raise RuntimeError("hipconfig not found")
    version = subprocess.run(
        [hipconfig, "--version"], capture_output=True, text=True
    )
    if not version.stdout.strip():
        raise RuntimeError(f"hipconfig --version returned no output: {version.stderr}")
    return parse(version.stdout.split()[-1].rstrip("-").replace("-", "+"))
